def solve(bilirubin_total, albumin, inr, ascites_grade, encephalopathy_grade):
    # Step 1: bilirubin_scoring - Assign points based on total bilirubin level (mg/dL) using the Child-Pugh criteria
    if bilirubin_total < 2:
        bilirubin_points = 1
    elif 2 <= bilirubin_total <= 3:
        bilirubin_points = 2
    else:  # bilirubin_total > 3
        bilirubin_points = 3
    yield {
        "step_name": "bilirubin_scoring",
        "step_description": "Assign points based on total bilirubin level (mg/dL) using the Child-Pugh criteria: <2 mg/dL -> 1, 2-3 mg/dL -> 2, >3 mg/dL -> 3",
        "step_result": bilirubin_points,
        "unit": None
    }

    # Step 2: albumin_scoring - Assign points based on serum albumin level (g/dL) using the Child-Pugh criteria
    if albumin > 3.5:
        albumin_points = 1
    elif 2.8 <= albumin <= 3.5:
        albumin_points = 2
    else:  # albumin < 2.8
        albumin_points = 3
    yield {
        "step_name": "albumin_scoring",
        "step_description": "Assign points based on serum albumin level (g/dL) using the Child-Pugh criteria: >3.5 g/dL -> 1, 2.8-3.5 g/dL -> 2, <2.8 g/dL -> 3",
        "step_result": albumin_points,
        "unit": None
    }

    # Step 3: inr_scoring - Assign points based on INR value using the Child-Pugh criteria
    if inr < 1.7:
        inr_points = 1
    elif 1.7 <= inr <= 2.3:
        inr_points = 2
    else:  # inr > 2.3
        inr_points = 3
    yield {
        "step_name": "inr_scoring",
        "step_description": "Assign points based on INR value using the Child-Pugh criteria: <1.7 -> 1, 1.7-2.3 -> 2, >2.3 -> 3",
        "step_result": inr_points,
        "unit": None
    }

    # Step 4: ascites_scoring - Assign points based on ascites severity using the Child-Pugh criteria
    if ascites_grade == 'Absent':
        ascites_points = 1
    elif ascites_grade == 'Slight':
        ascites_points = 2
    elif ascites_grade == 'Moderate':
        ascites_points = 3
    else:
        raise ValueError("Invalid ascites_grade: must be 'Absent', 'Slight', or 'Moderate'")
    yield {
        "step_name": "ascites_scoring",
        "step_description": "Assign points based on ascites severity using the Child-Pugh criteria: 'Absent' -> 1, 'Slight' -> 2, 'Moderate' -> 3",
        "step_result": ascites_points,
        "unit": None
    }

    # Step 5: encephalopathy_scoring - Assign points based on encephalopathy grade using the Child-Pugh criteria
    if encephalopathy_grade == 'None':
        encephalopathy_points = 1
    elif encephalopathy_grade == 'Grade1-2':
        encephalopathy_points = 2
    elif encephalopathy_grade == 'Grade3-4':
        encephalopathy_points = 3
    else:
        raise ValueError("Invalid encephalopathy_grade: must be 'None', 'Grade1-2', or 'Grade3-4'")
    yield {
        "step_name": "encephalopathy_scoring",
        "step_description": "Assign points based on encephalopathy grade using the Child-Pugh criteria: 'None' -> 1, 'Grade1-2' -> 2, 'Grade3-4' -> 3",
        "step_result": encephalopathy_points,
        "unit": None
    }

    # Step 6: child_pugh_sum - Calculate the total Child-Pugh Score by summing points from all five criteria
    child_pugh_score = bilirubin_points + albumin_points + inr_points + ascites_points + encephalopathy_points
    yield {
        "step_name": "child_pugh_sum",
        "step_description": "Calculate the total Child-Pugh Score by summing points from all five criteria: bilirubin, albumin, INR, ascites, encephalopathy",
        "step_result": child_pugh_score,
        "unit": None
    }

    return child_pugh_score
